import pandas as pd
import re

# 优先复用已暂存的小时数据；如小时数据某指标不可计算，再复用已暂存的汇总数据
cb_hourly_df_for_final = hourly_construction_building_pm25_aqi_staged_df
cb_summary_df_for_final = construction_building_20250602_pm25_aqi_staged_summary_df

def cb_norm_col(x):
    return re.sub(r"[^a-z0-9]", "", str(x).lower()).replace("pm2_5", "pm25")

def cb_find_hourly_col(df, target):
    for c in df.columns:
        n = cb_norm_col(c)
        if target == "pm25" and n in {"pm25", "pm25ugm3", "pm25value"}:
            return c
        if target == "aqi" and n == "aqi":
            return c
    for c in df.columns:
        n = cb_norm_col(c)
        if target == "pm25" and "pm25" in n and not any(k in n for k in ["mean", "avg", "max", "min", "count", "hour"]):
            return c
        if target == "aqi" and "aqi" in n and not any(k in n for k in ["mean", "avg", "max", "min", "count", "hour"]):
            return c
    return None

def cb_find_summary_col(df, metric):
    for c in df.columns:
        n = cb_norm_col(c)
        if metric == "mean_pm25" and (n == "meanpm25" or (("mean" in n or "avg" in n or "average" in n) and "pm25" in n)):
            return c
        if metric == "max_pm25" and (n == "maxpm25" or (("max" in n or "peak" in n) and "pm25" in n)):
            return c
        if metric == "mean_aqi" and (n == "meanaqi" or (("mean" in n or "avg" in n or "average" in n) and "aqi" in n)):
            return c
        if metric == "exceedance_hours" and (n == "exceedancehours" or ("exceedance" in n and "hour" in n) or ("pm25" in n and "75" in n and ("hour" in n or "count" in n))):
            return c
    return None

cb_pm25_col_final = cb_find_hourly_col(cb_hourly_df_for_final, "pm25")
cb_aqi_col_final = cb_find_hourly_col(cb_hourly_df_for_final, "aqi")

cb_pm25_series_final = pd.to_numeric(cb_hourly_df_for_final[cb_pm25_col_final], errors="coerce").dropna() if cb_pm25_col_final else pd.Series(dtype="float64")
cb_aqi_series_final = pd.to_numeric(cb_hourly_df_for_final[cb_aqi_col_final], errors="coerce").dropna() if cb_aqi_col_final else pd.Series(dtype="float64")

cb_summary_row_final = cb_summary_df_for_final.iloc[0] if len(cb_summary_df_for_final) > 0 else None

if len(cb_pm25_series_final) > 0:
    mean_pm25 = float(cb_pm25_series_final.mean())
    max_pm25 = float(cb_pm25_series_final.max())
    exceedance_hours = int((cb_pm25_series_final > 75).sum())
else:
    cb_mean_pm25_summary_col = cb_find_summary_col(cb_summary_df_for_final, "mean_pm25")
    cb_max_pm25_summary_col = cb_find_summary_col(cb_summary_df_for_final, "max_pm25")
    cb_exceedance_summary_col = cb_find_summary_col(cb_summary_df_for_final, "exceedance_hours")
    if cb_summary_row_final is None or not all([cb_mean_pm25_summary_col, cb_max_pm25_summary_col, cb_exceedance_summary_col]):
        raise ValueError("暂存数据中无法取得 PM2.5 均值、最大值或 PM2.5>75 小时数，未写入静默零值。")
    mean_pm25 = float(cb_summary_row_final[cb_mean_pm25_summary_col])
    max_pm25 = float(cb_summary_row_final[cb_max_pm25_summary_col])
    exceedance_hours = int(cb_summary_row_final[cb_exceedance_summary_col])

if len(cb_aqi_series_final) > 0:
    mean_aqi = float(cb_aqi_series_final.mean())
else:
    cb_mean_aqi_summary_col = cb_find_summary_col(cb_summary_df_for_final, "mean_aqi")
